import { Avatar, EmptyState, PageHeading, ProgressBar, SectionCard, StatusBadge } from "@/components/shared";
import { requireUser } from "@/lib/auth";
import { getGuardianPortal } from "@/lib/data";
import { formatTanggal, rataNilai } from "@/lib/utils";
import { BookHeart, HeartHandshake, MessageCircleHeart, Sparkles } from "lucide-react";
import { redirect } from "next/navigation";

export default async function GuardianPortalPage() {
  const user = await requireUser();
  if (user.role !== "wali") redirect("/dashboard?galat=Portal%20ini%20khusus%20Wali%20Santri.");
  const data = await getGuardianPortal(user.id);
  return <><PageHeading eyebrow="Portal Wali Santri" title={`Assalamu'alaikum, ${data.parent?.name ?? user.name}`} description="Pantau perkembangan hafalan anak, lihat catatan dari musyrif, dan berikan dukungan terbaik dari rumah." action={<span className="inline-flex items-center gap-2 rounded-xl border border-rose-100 bg-rose-50 px-3 py-2 text-xs font-bold text-rose-700"><HeartHandshake size={16}/>Terhubung sebagai wali</span>}/>{data.children.length ? <div className="space-y-5">{data.children.map((child) => { const detail = child.detail; if (!detail) return null; return <article key={child.id} className="overflow-hidden rounded-3xl border border-slate-200 bg-white shadow-sm"><div className="bg-gradient-to-r from-emerald-950 to-emerald-800 p-5 text-white sm:p-6"><div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between"><div className="flex items-center gap-3"><Avatar name={child.name} className="size-12 bg-amber-400 text-emerald-950"/><div><p className="font-display text-2xl font-bold">{child.name}</p><p className="mt-1 text-xs text-emerald-200">{child.nis} · {child.className ?? "Kelas belum diatur"} · {child.halaqahName ?? "Halaqah belum diatur"}</p></div></div><div className="rounded-xl bg-white/10 px-4 py-2"><p className="text-[10px] font-bold uppercase tracking-wider text-emerald-200">Nilai rata-rata</p><p className="font-display text-2xl font-bold text-amber-300">{detail.averageScore || "—"}</p></div></div></div><div className="grid gap-5 p-5 lg:grid-cols-[.9fr_1.1fr]"><section><div className="rounded-2xl bg-emerald-50 p-4"><div className="flex items-center justify-between"><div><p className="text-xs font-bold text-emerald-700">Capaian hafalan</p><p className="mt-1 font-display text-3xl font-bold text-emerald-950">{detail.progress.percentage}%</p></div><BookHeart className="text-emerald-600" size={28}/></div><p className="mt-2 text-xs text-emerald-800">{detail.progress.verses} ayat lulus · {detail.progress.surahCount} surah tercatat</p><div className="mt-3"><ProgressBar value={detail.progress.percentage}/></div></div><div className="mt-4"><h3 className="flex items-center gap-2 text-sm font-bold text-slate-800"><Sparkles size={16} className="text-amber-500"/>Target pembinaan</h3>{detail.targets.length ? detail.targets.map((target) => <div className="mt-2 rounded-xl border border-slate-100 p-3" key={target.id}><p className="text-xs font-bold text-slate-700">{target.programName}</p><p className="mt-1 text-xs text-slate-500">Target harian {target.dailyTarget} · mingguan {target.weeklyTarget}</p></div>) : <p className="mt-2 text-xs leading-5 text-slate-500">Belum ada target khusus yang ditetapkan pada sistem.</p>}</div></section><section><h3 className="flex items-center gap-2 text-sm font-bold text-slate-800"><MessageCircleHeart size={17} className="text-rose-500"/>Catatan terbaru dari musyrif</h3><div className="mt-3 divide-y divide-slate-100 rounded-2xl border border-slate-100">{detail.submissions.length ? detail.submissions.slice(0, 3).map((item) => <div key={item.id} className="p-3.5"><div className="flex flex-wrap items-center justify-between gap-2"><p className="text-sm font-bold text-slate-800">{item.surah} · ayat {item.verseStart}–{item.verseEnd}</p><StatusBadge value={item.status}/></div><p className="mt-1 text-xs text-slate-500">{formatTanggal(item.submissionDate)} · Nilai {rataNilai(item.fluencyScore, item.tajwidScore, item.makhrajScore)}</p><p className="mt-2 text-xs leading-5 text-slate-600">{item.notes ?? "Alhamdulillah, terus semangati ananda untuk istiqamah muraja'ah."}</p></div>) : <EmptyState title="Belum ada catatan" description="Catatan akan muncul setelah setoran pertama."/>}</div></section></div></article>; })}</div> : <EmptyState title="Belum ada anak terhubung" description="Silakan hubungi Admin Pondok untuk menghubungkan akun wali dengan data santri."/>}</>;
}
